parameters.functionCode:
// Validate email format properly
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

const errors = [];
if (!$json.name || $json.name.trim() === '') {
  errors.push('Name is required');
}
if (!$json.email || !emailRegex.test($json.email)) {
  errors.push('Valid email is required');
}
if (!$json.subject || $json.subject.trim() === '') {
  errors.push('Subject is required');
}
if (!$json.message || $json.message.trim() === '') {
  errors.push('Message body is required');
}

if (errors.length > 0) {
  const error = new Error(errors.join('; '));
  error.error_type = 'validation_error';
  error.http_code = 400;
  throw error;
}

return [{
  json: {
    ...$json,
    validation_passed: true
  }
}];

// Handle optional PDF attachment text if provided by upstream systems.
const attachment_filename = ($json.attachment_filename || '').trim();
const attachment_text = ($json.attachment_text || '').trim();

let processing_log = [];
let fulltext = $json.message || '';

if (attachment_filename) {
  if (attachment_text) {
    fulltext = `${fulltext}\n\n[Attachment: ${attachment_filename}]\n${attachment_text}`;
    processing_log.push('attachment_text_appended');
  } else {
    // Bonus requirement fallback: continue without attachment text if extraction failed/unavailable.
    processing_log.push(`attachment_present_but_no_text:${attachment_filename}`);
  }
}

return [{
  json: {
    ...$json,
    attachment_filename,
    attachment_text,
    fulltext,
    processing_log
  }
}];

const id = 'TCK-' + Date.now();

return [{
  json: {
    ...$json,
    ticket_id: id,
    timestamp: new Date().toISOString(),
    status: 'processing'
  }
}];

let classification;

function collectStrings(value, bucket) {
  if (value === null || value === undefined) return;
  if (typeof value === 'string') {
    bucket.push(value);
    return;
  }
  if (Array.isArray(value)) {
    for (const item of value) collectStrings(item, bucket);
    return;
  }
  if (typeof value === 'object') {
    for (const key of Object.keys(value)) collectStrings(value[key], bucket);
  }
}

function fallbackClassification(reason) {
  const blob = `${$json.subject || ''} ${$json.fulltext || $json.message || ''}`.toLowerCase();
  let urgency = 'low';
  if (/critical|urgent|security|breach|data loss|outage|down/.test(blob)) urgency = 'critical';
  else if (/cannot|can't|failed|error|blocked|broken/.test(blob)) urgency = 'high';
  else if (/issue|problem|slow|bug/.test(blob)) urgency = 'medium';

  let category = 'general';
  if (/bill|invoice|payment|refund|charge|price/.test(blob)) category = 'billing';
  else if (/feature|request|enhancement/.test(blob)) category = 'feature_request';
  else if (/error|login|auth|setup|api|integration|bug/.test(blob)) category = 'technical';

  const sentiment = /angry|frustrated|terrible|worst/.test(blob) ? 'angry' : (/bad|upset|not happy/.test(blob) ? 'negative' : 'neutral');

  return {
    category,
    urgency,
    sentiment,
    confidence: 0.35,
    summary: `Fallback classification used: ${reason}`
  };
}

try {
  const textCandidates = [];
  collectStrings($json, textCandidates);

  let parsed = null;
  let rawExtract = '';

  for (const candidate of textCandidates) {
    const match = String(candidate).match(/\{[\s\S]*\}/);
    if (!match) continue;

    try {
      parsed = JSON.parse(match[0]);
      rawExtract = match[0];
      break;
    } catch (e) {
      // keep scanning other candidates
    }
  }

  if (!parsed) {
    classification = fallbackClassification('no_json_in_ai_response');
    return [{
      json: {
        ...$json,
        ...classification,
        ai_validation_passed: false,
        ai_validation_warning: 'No JSON object found in AI response',
        ai_response_raw: textCandidates.join('\n').slice(0, 2000)
      }
    }];
  }

  classification = parsed;

  const required = ['category', 'urgency', 'sentiment', 'confidence', 'summary'];
  for (const field of required) {
    if (!(field in classification)) {
      throw new Error(`Missing required field: ${field}`);
    }
  }

  const validUrgencies = ['critical', 'high', 'medium', 'low'];
  classification.urgency = String(classification.urgency || '').toLowerCase();
  if (!validUrgencies.includes(classification.urgency)) {
    throw new Error(`Invalid urgency: ${classification.urgency}`);
  }

  classification.category = String(classification.category || 'other').toLowerCase();
  classification.sentiment = String(classification.sentiment || 'neutral').toLowerCase();
  classification.confidence = Number(classification.confidence);

  if (Number.isNaN(classification.confidence) || classification.confidence < 0 || classification.confidence > 1) {
    throw new Error(`Invalid confidence score: ${classification.confidence}`);
  }

  return [{
    json: {
      ...$json,
      ...classification,
      ai_validation_passed: true,
      ai_response_raw: rawExtract
    }
  }];
} catch (e) {
  const fallback = fallbackClassification(e.message);
  return [{
    json: {
      ...$json,
      ...fallback,
      ai_validation_passed: false,
      ai_validation_warning: `AI Output Validation Error: ${e.message}`,
      ai_response_raw: ''
    }
  }];
}

// Normalize embedding output and restore upstream fields for downstream HTTP/function nodes.
const base = ($item(0).$node['Function — Validate Classification'] || {}).json || {};

const candidates = [
  $json.embedding,
  $json.data?.[0]?.embedding,
  $json.response?.data?.[0]?.embedding,
  $json.body?.data?.[0]?.embedding
];

const vector = candidates.find((v) => Array.isArray(v) && v.length > 0);
if (!vector) {
  throw new Error('Embedding vector not found in OpenAI response');
}

return [{
  json: {
    ...base,
    qdrant_vector: vector,
    embedding_dimension: vector.length
  }
}];

// Process Qdrant results and compute retrieval confidence using weighted average
const rawResults = ($json.result && $json.result.result) || 
                   ($json.result && Array.isArray($json.result) ? $json.result : null) ||
                   [];

const threshold = 0.5;  // 50% threshold
const results = Array.isArray(rawResults) ? rawResults : [];
const knowledge_sources = [];
let knowledge_context = '';
let all_sources = [];

// Calculate weights for top 3 results (exponential decay)
// Position 1: weight 0.5, Position 2: weight 0.3, Position 3: weight 0.2
const weights = [0.5, 0.3, 0.2];

if (results.length > 0) {
    knowledge_context = '=== KNOWLEDGE BASE ARTICLES (Top 3 Results) ===\n\n';

    // Process only top 3 results
    const topResults = results.slice(0, 3);

    for (let i = 0; i < topResults.length; i++) {
        const item = topResults[i] || {};
        const payload = item.payload || {};
        const source = payload.source || 'Unknown';
        const title = payload.title || payload.source || 'Knowledge Article';
        const content = payload.content || payload.text || '';
        const score = Number(item.score || 0);

        // Track unique sources
        if (!all_sources.includes(source)) {
            all_sources.push(source);
        }

        knowledge_sources.push({
            id: i + 1,
            source: source,
            title: title,
            score: score,
            score_percent: (score * 100).toFixed(1),
            weight: weights[i],
            weighted_contribution: (score * weights[i]).toFixed(4)
        });

        // Format for display in prompt
        knowledge_context += `[ARTICLE ${i+1}] (Weight: ${weights[i] * 100}%)\n`;
        knowledge_context += `Source: ${source}\n`;
        knowledge_context += `Title: ${title}\n`;
        knowledge_context += `Relevance Score: ${(score * 100).toFixed(1)}%\n`;
        knowledge_context += `Weighted Contribution: ${(score * weights[i] * 100).toFixed(1)}%\n`;
        knowledge_context += `Content: ${String(content).substring(0, 500)}\n`;
        knowledge_context += `---\n\n`;
    }

    // Calculate weighted average score
    let weightedSum = 0;
    let weightTotal = 0;

    for (let i = 0; i < Math.min(topResults.length, weights.length); i++) {
        weightedSum += knowledge_sources[i].score * weights[i];
        weightTotal += weights[i];
    }

    const weighted_avg_score = weightedSum / weightTotal;
    const retrieval_score = weighted_avg_score;
    const retrieval_low_confidence = retrieval_score < threshold;
    const retrieval_confidence_percent = (retrieval_score * 100).toFixed(1);

    // Calculate individual scores for logging
    const individual_scores = knowledge_sources.map(s => ({
        source: s.source,
        score: s.score_percent,
        weight: s.weight * 100
    }));

    // Add calculation details to context
    knowledge_context += `=== RETRIEVAL CONFIDENCE CALCULATION ===\n`;
    knowledge_context += `Weighted Average Formula: (Score1 × 0.5) + (Score2 × 0.3) + (Score3 × 0.2)\n`;
    knowledge_context += `Calculation: `;
    for (let i = 0; i < knowledge_sources.length; i++) {
        knowledge_context += `(${knowledge_sources[i].score_percent}% × ${weights[i] * 100}%)`;
        if (i < knowledge_sources.length - 1) knowledge_context += ` + `;
    }
    knowledge_context += `\n`;
    knowledge_context += `Result: ${retrieval_confidence_percent}%\n`;
    knowledge_context += `Threshold: ${threshold * 100}%\n`;
    knowledge_context += `Status: ${retrieval_low_confidence ? 'BELOW THRESHOLD - Using general knowledge' : 'ABOVE THRESHOLD - Using knowledge base'}\n`;
    knowledge_context += `---\n\n`;

    if (retrieval_low_confidence) {
        knowledge_context += `⚠️ NOTE: Weighted confidence (${retrieval_confidence_percent}%) is below ${threshold * 100}% threshold.\n`;
        knowledge_context += `Response will include: "No specific policy found — this response is based on general knowledge."\n`;
    }

} else {
    knowledge_context = 'No specific knowledge base articles found.';
}

// If no results, set default values
const retrieval_score = knowledge_sources.length > 0 ? 
    (knowledge_sources.reduce((sum, s, i) => sum + (s.score * weights[i]), 0) / weights.reduce((a, b) => a + b, 0)) : 0;
const retrieval_low_confidence = retrieval_score < threshold;
const retrieval_confidence_percent = (retrieval_score * 100).toFixed(1);

// Build processing log with detailed info
const existingLog = Array.isArray($json.processing_log) ? $json.processing_log : [];
const processing_log = [
    ...existingLog,
    `knowledge_chunks_retrieved:${results.length}`,
    `top_chunks_used:${Math.min(results.length, 3)}`,
    `unique_sources:${all_sources.length}`,
    `sources_found:${all_sources.join(', ')}`,
    `weighted_avg_score:${retrieval_score.toFixed(4)} (${retrieval_confidence_percent}%)`,
    `individual_scores:${knowledge_sources.map(s => `${s.source}=${s.score_percent}%`).join(', ')}`,
    `threshold:${threshold * 100}%`,
    `retrieval_low_confidence:${retrieval_low_confidence}`,
    `weight_calculation:${knowledge_sources.map((s, i) => `${s.score_percent}%×${weights[i]*100}%`).join(' + ')} = ${retrieval_confidence_percent}%`
];

// Preserve all original data
const outputData = {
    // Original ticket data
    ticket_id: $json.ticket_id,
    timestamp: $json.timestamp,
    name: $json.name,
    email: $json.email,
    subject: $json.subject,
    message: $json.message,
    fulltext: $json.fulltext,
    attachment_filename: $json.attachment_filename,
    attachment_text: $json.attachment_text,

    // Classification data
    category: $json.category,
    urgency: $json.urgency,
    sentiment: $json.sentiment,
    confidence: $json.confidence,
    summary: $json.summary,
    ai_validation_passed: $json.ai_validation_passed,

    // Knowledge data
    knowledge_context: knowledge_context,
    knowledge_sources: knowledge_sources,
    all_sources_found: all_sources,
    retrieval_score: retrieval_score,
    retrieval_low_confidence: retrieval_low_confidence,
    retrieval_confidence_percent: retrieval_confidence_percent,
    weighted_calculation: {
        weights: weights,
        sources: knowledge_sources,
        formula: "Weighted Average = (Score1 × 0.5) + (Score2 × 0.3) + (Score3 × 0.2)",
        result_percent: retrieval_confidence_percent
    },

    // Processing data
    status: $json.status || 'processing',
    processing_log: processing_log,
    validation_passed: $json.validation_passed
};

return [{
    json: outputData
}];

