=You are a professional customer support specialist.

Generate an internal draft response based on the ticket information below.

TICKET INFORMATION:
Name: {{ $json.name }}
Subject: {{$json.subject}}
Customer Message: {{$json.message}}
Category: {{$json.category}}
Urgency: {{$json.urgency}}
Sentiment: {{$json.sentiment}}

RETRIEVAL STATUS:
Retrieval Confidence Score: {{$json.retrieval_confidence_percent}}%
Threshold: 50%
Low Confidence Flag: {{$json.retrieval_low_confidence}}

KNOWLEDGE BASE CONTENT (if available):
{{$json.knowledge_context}}

INSTRUCTIONS:
1. Match your tone to the customer sentiment ({{$json.sentiment}})
2. Use concise, actionable language
3. IMPORTANT - Check the Retrieval Confidence Score:
   - If score is BELOW 50% (Low Confidence Flag = true), you MUST include this exact sentence:
     "No specific policy found — this response is based on general knowledge."
   - If score is ABOVE 50%, reference the actual content from the Knowledge Base above
4. End the response with: "This is a draft response pending support team review."

Now generate the draft response:

parameters.functionCode:
const aiDraft =
  $json.message?.content ||
  $json.output_text ||
  $json.text ||
  $json.content ||
  '';

const confidenceNum = Number($json.confidence);
const confidence = Number.isFinite(confidenceNum) ? confidenceNum : 0;

let status = 'normal';
let needs_review = false;
if (confidence < 0.6) {
  status = 'needs-manual-review';
  needs_review = true;
}

const existingLog = Array.isArray($json.processing_log) ? $json.processing_log : [];
const processing_log = [
  ...existingLog,
  `ai_confidence:${confidence.toFixed(4)}`,
  `status:${status}`,
];

return [{
  json: {
    ...$json,
    confidence,
    draft_response: aiDraft,
    knowledge_sources: $json.knowledge_sources || [],
    status,
    needs_manual_review: needs_review,
    processing_log,
  },
}];

parameters.jsCode:
const text = `${$json.subject || ''} ${$json.message || ''}`.toLowerCase();

const hasHardHighSignals =
  /(outage|system down|data loss|security breach|all customers|payment down|cannot login|service unavailable)/.test(text);

const hasMediumSignals =
  /(minor|formatting|single report|not urgent|next few days|non-critical|no outage|optional column)/.test(text);

// If classifier said high but ticket text clearly indicates medium and no hard-high signal, downgrade.
let urgency = String($json.urgency || '').toLowerCase();
if (urgency === 'high' && hasMediumSignals && !hasHardHighSignals) {
  urgency = 'medium';
}

return [{
  json: {
    ...$json,
    urgency
  }
}];

parameters.functionCode:
const processing_log = Array.isArray($json.processing_log) ? $json.processing_log.join(' | ') : '';

const draft_response = typeof $json.draft_response === 'string'
  ? $json.draft_response
  : ($json.draft_response?.content || JSON.stringify($json.draft_response || ''));

return [{
  json: {
    ticket_id: $json.ticket_id,
    timestamp: $json.timestamp,
    name: $json.name,
    email: $json.email,
    subject: $json.subject,
    category: $json.category,
    urgency: $json.urgency,
    sentiment: $json.sentiment,
    confidence: $json.confidence,
    ai_summary: $json.summary,
    draft_response,
    knowledge_sources: JSON.stringify($json.knowledge_sources || []),
    status: $json.status,
    processing_log
  }
}];

// Get the error data
const errorData = $json.error_details || $json.error || $json;

// Extract timestamp
const timestamp = new Date().toISOString();

// Extract error message
let errorMessage = 'Unknown error';
if (errorData.message) {
    errorMessage = errorData.message;
} else if ($json.error?.message) {
    errorMessage = $json.error.message;
}

// Extract error type
let errorType = 'processing_error';
if (errorData.type) {
    errorType = errorData.type;
} else if ($json.error?.type) {
    errorType = $json.error.type;
} else if (errorMessage.includes('required')) {
    errorType = 'validation_error';
}

// Extract ticket ID
let ticketId = 'N/A';
if (errorData.ticket_id) {
    ticketId = errorData.ticket_id;
} else if ($json.error?.ticket_id) {
    ticketId = $json.error.ticket_id;
}

// Extract error stack
let errorStack = '';
if (errorData.stack) {
    errorStack = errorData.stack;
} else if (errorData.error?.stack) {
    errorStack = errorData.error.stack;
} else if ($json.error?.stack) {
    errorStack = $json.error.stack;
} else {
    errorStack = `Error: ${errorMessage}\nType: ${errorType}\nTimestamp: ${timestamp}`;
}
errorStack = errorStack.substring(0, 1000);

// Extract node name - try to get from available data
let nodeName = 'Unknown';
if (errorData.node_name) {
    nodeName = errorData.node_name;
} else if (errorData.nodeName) {
    nodeName = errorData.nodeName;
} else if ($json.error?.node_name) {
    nodeName = $json.error.node_name;
} else {
    // Try to determine from error message or stack
    if (errorMessage.includes('validation') || errorMessage.includes('required')) {
        nodeName = 'Function — Validate Input';
    } else if (errorStack.includes('OpenAI')) {
        nodeName = 'OpenAI Node';
    } else if (errorStack.includes('Qdrant')) {
        nodeName = 'Qdrant Search';
    }
}

// Extract HTTP status
let httpStatus = 500;
if (errorData.http_status) {
    httpStatus = errorData.http_status;
} else if (errorData.http_code) {
    httpStatus = errorData.http_code;
} else if ($json.statusCode) {
    httpStatus = $json.statusCode;
} else if ($json.error?.http_code) {
    httpStatus = $json.error.http_code;
} else if (errorType === 'validation_error') {
    httpStatus = 400;
}

// Extract input data - try to reconstruct from available information
let inputData = '';
if (errorData.input_data) {
    inputData = JSON.stringify(errorData.input_data).substring(0, 500);
} else if (errorData.input) {
    inputData = JSON.stringify(errorData.input).substring(0, 500);
} else if ($json.error?.input_data) {
    inputData = JSON.stringify($json.error.input_data).substring(0, 500);
} else {
    // Try to extract from the error object
    const possibleInput = errorData.received_data || errorData.details || errorData.originalError;
    if (possibleInput) {
        inputData = JSON.stringify(possibleInput).substring(0, 500);
    } else {
        // Look for input in the execution data
        inputData = 'No input data captured';
    }
}

// Return all 8 fields
return [{
    json: {
        timestamp: timestamp,
        error_message: errorMessage.substring(0, 500),
        error_type: errorType,
        ticket_id: ticketId,
        error_stack: errorStack,
        node_name: nodeName,
        http_status: httpStatus,
        input_data: inputData
    }
}];

// Check if there's an error in the input
let errorData = $json.error || $json;

// If error is a string, try to parse it
if (typeof errorData === 'string') {
    try {
        errorData = JSON.parse(errorData);
    } catch(e) {
        errorData = { message: errorData };
    }
}

// Extract error message from various possible locations
let errorMessage = 'Unknown error occurred';
if (errorData.message) {
    errorMessage = errorData.message;
} else if (errorData.error?.message) {
    errorMessage = errorData.error.message;
} else if (typeof errorData === 'string') {
    errorMessage = errorData;
} else if (errorData.json?.message) {
    errorMessage = errorData.json.message;
}

// Extract error type
let errorType = 'processing_error';
if (errorData.error_type) {
    errorType = errorData.error_type;
} else if (errorData.type) {
    errorType = errorData.type;
} else if (errorMessage.includes('validation') || errorMessage.includes('required')) {
    errorType = 'validation_error';
} else if (errorMessage.includes('authentication') || errorMessage.includes('API key')) {
    errorType = 'authentication_error';
}

// Extract HTTP status code
let httpCode = errorData.http_code || 500;
if (errorType === 'validation_error') httpCode = 400;
else if (errorType === 'authentication_error') httpCode = 401;

// Extract ticket ID if available
const ticketId = errorData.ticket_id || errorData.input?.ticket_id || null;

// Format error response
const errorResponse = {
    success: false,
    error: {
        message: errorMessage,
        type: errorType,
        timestamp: new Date().toISOString(),
        ticket_id: ticketId
    },
    statusCode: httpCode
};

// Log full error for debugging
console.error('Workflow Error Details:', {
    originalError: errorData,
    parsedError: errorResponse.error
});

return [{
    json: errorResponse
}];
